107	#[test]
108	fn lemmas_and_restrictions_fixture() {
109	    // Full mirror of MacroInLemmasAndRestrictions vs lemmas_expanded.spthy.
110	    let x = var("x", SortHint::Untagged);
111	    let y = var("y", SortHint::Untagged);
112	    let macros = TheoryItem::Macros(vec![
113	        mdef("m", &[x.clone()], msg("x")),
114	        mdef("m2", &[x.clone(), y.clone()], pair(vec![msg("x"), msg("y")])),
115	        mdef("m3", &[x.clone()], msg("x")),
116	    ]);
117	    let macros_kept = macros.clone(); // declarations are preserved in place [Q37]
118	    // rule A: [In(x)] --[A(m(x))]-> []
119	    let a = rule_act("A", vec![fact("In", vec![msg("x")])],
120	                     fact("A", vec![app("m", vec![msg("x")])]));
121	    // rule B: [In(x),In(y)] --[B(m2(x,y))]-> []
122	    let b = rule_act("B", vec![fact("In", vec![msg("x")]), fact("In", vec![msg("y")])],
123	                     fact("B", vec![app("m2", vec![msg("x"), msg("y")])]));
124	    // restriction: All x #i. A(m(m3(x)))@i ==> Ex y. x=y
125	    let restr = TheoryItem::Restriction(Restriction {
126	        name: "OnlyValidProcessing".into(),
127	        attributes: vec![],
128	        formula: Formula::Forall(
129	            vec![x.clone(), var("i", SortHint::Node)],
130	            Box::new(Formula::Implies(
131	                Box::new(Formula::Atom(Atom::Action(
132	                    fact("A", vec![app("m", vec![app("m3", vec![msg("x")])])]),
133	                    Term::Var(var("i", SortHint::Node)),
134	                ))),
135	                Box::new(Formula::Exists(
136	                    vec![y.clone()],
137	                    Box::new(Formula::Atom(Atom::Eq(msg("x"), msg("y")))),
138	                )),
139	            )),
140	        ),
141	    });
142	    // lemma M: exists-trace "Ex x #i. A(m(x))@i"
143	    let lem = TheoryItem::Lemma(Lemma {
144	        name: "M".into(),
145	        modulo: None,
146	        attributes: vec![],
147	        trace_quantifier: TraceQuantifier::ExistsTrace,
148	        formula: Formula::Exists(
149	            vec![x.clone(), var("i", SortHint::Node)],
150	            Box::new(Formula::Atom(Atom::Action(
151	                fact("A", vec![app("m", vec![msg("x")])]),
152	                Term::Var(var("i", SortHint::Node)),
153	            ))),
154	        ),
155	        proof: None,
156	        plaintext: String::new(),
157	    });
158	    let out = expand(&theory(vec![macros, TheoryItem::Rule(a), TheoryItem::Rule(b), restr, lem]));
159	
160	    // Expected macro-free equivalent.
161	    let a_e = rule_act("A", vec![fact("In", vec![msg("x")])], fact("A", vec![msg("x")]));
162	    let b_e = rule_act("B", vec![fact("In", vec![msg("x")]), fact("In", vec![msg("y")])],
163	                       fact("B", vec![pair(vec![msg("x"), msg("y")])]));
164	    let restr_e = TheoryItem::Restriction(Restriction {
165	        name: "OnlyValidProcessing".into(),
166	        attributes: vec![],
167	        formula: Formula::Forall(
168	            vec![x.clone(), var("i", SortHint::Node)],
169	            Box::new(Formula::Implies(
170	                Box::new(Formula::Atom(Atom::Action(
171	                    fact("A", vec![msg("x")]), Term::Var(var("i", SortHint::Node)),
172	                ))),
173	                Box::new(Formula::Exists(
174	                    vec![y.clone()],
175	                    Box::new(Formula::Atom(Atom::Eq(msg("x"), msg("y")))),
176	                )),
177	            )),
178	        ),
179	    });
180	    let lem_e = TheoryItem::Lemma(Lemma {
181	        name: "M".into(),
182	        modulo: None,
183	        attributes: vec![],
184	        trace_quantifier: TraceQuantifier::ExistsTrace,
185	        formula: Formula::Exists(
186	            vec![x.clone(), var("i", SortHint::Node)],
187	            Box::new(Formula::Atom(Atom::Action(
188	                fact("A", vec![msg("x")]), Term::Var(var("i", SortHint::Node)),
189	            ))),
190	        ),
191	        proof: None,
192	        plaintext: String::new(),
193	    });
194	    let expected = theory(vec![
195	        macros_kept, TheoryItem::Rule(a_e), TheoryItem::Rule(b_e), restr_e, lem_e,
196	    ]);
197	    assert_eq!(out, expected);
198	}
